export function findRoute(origin: string, destination: string): TransferRoute | undefined {
  const o = origin.trim().toLowerCase();
  const d = destination.trim().toLowerCase();
  return TRANSFER_ROUTES.find(r => r.origin.toLowerCase() === o && r.destination.toLowerCase() === d)
    || TRANSFER_ROUTES.find(r => r.origin.toLowerCase() === d && r.destination.toLowerCase() === o);
}
